// ============================================================
// Calculer les relances dues
// ============================================================
// Pour chaque envoi non répondu, vérifier si le délai de
// relance est dépassé selon la config :
//   statut=envoye    → relance_1 si date_envoi + delai_1 dépassé
//   statut=relance_1 → relance_2 si date_derniere_relance + delai_2 dépassé
//   statut=relance_2 → relance_3 si date_derniere_relance + delai_3 dépassé
//   statut=relance_3 → plus de relance (max atteint)
//   statut=repondu   → ignoré
// ============================================================

const envois = $input.all().map(item => item.json);
const configRows = $('Lire Config').all().map(item => item.json);

// Lire les délais depuis la config (clé/valeur)
function getConfigValue(key, defaultVal) {
  const row = configRows.find(r => r.cle === key || r.key === key || r.parametre === key);
  return row ? parseInt(row.valeur || row.value || defaultVal) : defaultVal;
}

const delai1 = getConfigValue('delai_relance_1', 2);
const delai2 = getConfigValue('delai_relance_2', 5);
const delai3 = getConfigValue('delai_relance_3', 10);

const now = new Date();
const relancesDues = [];

for (const envoi of envois) {
  const statut = envoi.statut;
  if (!statut || statut === 'repondu' || statut === 'relance_3') continue;

  let dateRef, delai, prochainStatut, numRelance;

  if (statut === 'envoye') {
    dateRef = envoi.date_envoi;
    delai = delai1;
    prochainStatut = 'relance_1';
    numRelance = 1;
  } else if (statut === 'relance_1') {
    dateRef = envoi.date_derniere_relance || envoi.date_envoi;
    delai = delai2;
    prochainStatut = 'relance_2';
    numRelance = 2;
  } else if (statut === 'relance_2') {
    dateRef = envoi.date_derniere_relance || envoi.date_envoi;
    delai = delai3;
    prochainStatut = 'relance_3';
    numRelance = 3;
  } else {
    continue;
  }

  if (!dateRef) continue;

  const dateEnvoi = new Date(dateRef);
  const diffJours = Math.floor((now - dateEnvoi) / (1000 * 60 * 60 * 24));

  if (diffJours >= delai) {
    relancesDues.push({
      ...envoi,
      prochain_statut: prochainStatut,
      num_relance: numRelance,
      nb_relances: (parseInt(envoi.nb_relances) || 0) + 1,
      jours_depuis_envoi: diffJours
    });
  }
}

return relancesDues.map(r => ({ json: r }));

// ============================================================
// Construire l'URL pré-remplie selon le type de questionnaire
// ============================================================
// Mapping type → Google Form ID :
//   positionnement → FORMS_POSITIONNEMENT
//   satisfaction   → FORMS_SATISFACTION
//   evaluation     → FORMS_EVALUATION
//   suivi_froid    → FORMS_SUIVI_FROID
// ============================================================

const item = $json;

const formIds = {
  'positionnement': '1Tkf-lm7Kd_6EaN7-MXja1zAhAKxqH-j1gOVONl7fUDA',
  'satisfaction':   '1vjF6Dxw0QgPbJHA_7HBMFnJApcHmLWK9amGm-S5FHfQ',
  'evaluation':     '1DM9QfOGbClRhxEw8jT6rPIz5mk7_cO_AvxN3OyYjLLg',
  'suivi_froid':    '1h63PHGz4mTa-4NnY8Na-VUC8lN4jMLNnR9b3Jm-1Twc'
};

const type = item.type || 'positionnement';
const formId = formIds[type] || formIds['positionnement'];

const baseUrl = `https://docs.google.com/forms/d/e/${formId}/viewform`;
const params = new URLSearchParams({
  'entry.inscription_id': item.inscription_id || '',
  'entry.session_id': item.session_id || '',
  'entry.apprenant_nom': item.apprenant_nom || item.nom || '',
  'entry.apprenant_prenom': item.apprenant_prenom || item.prenom || ''
});

const url = `${baseUrl}?${params.toString()}`;

// Labels pour l'email
const typeLabels = {
  'positionnement': 'positionnement',
  'satisfaction': 'satisfaction',
  'evaluation': 'évaluation des acquis',
  'suivi_froid': 'suivi à froid'
};

return [{
  json: {
    ...item,
    url_formulaire: url,
    type_label: typeLabels[type] || type
  }
}];
